// NORMALIZE LEAD + DORMANT EST (Updated Cadence v3)
// Cadence: Day_1 → Day_30 → Day_60 → Day_90 → Done
//
// LEGACY MIGRATION (existing tracker / Last_Sequence_Step_Sent__c):
//   blank/null/NONE with no real prior sequence → Day_1
//   old Day_0 / Day0 / Day 0 → updated Day_30
//   old Day_1 → updated Day_30
//   old Day_7 → updated Day_30
//   old Day_15 → updated Day_30
//   old Day_30 (legacy) → updated Day_60
//   old Day_45 → updated Day_60
//   old Day_60 → Review_Only (no updated Day_90 email)
//
// FRESH LEAD: no EST tracker at all → Day_1 email only
//
// Legacy Day_30 due-date recalc base = Last_Sequence_Email_Sent_At__c:
//   Day_0 +30, Day_1 +29, Day_7 +23, Day_15 +15
// If email timestamp missing for Day_0/1/7/15: use Next_Follow_Up_Date_Lead__c;
// if both missing → skip with missing legacy timestamp (do not guess).

const cfg = $('Dormant Sequence Config').item.json;
const leadItems = $('Query Dormant Leads').all();
const PROCESS_LIMIT = Number(cfg.processLimit) || 20;

const estByKey = {};
try {
  for (const r of $('Find Dormant EST Record').all()) {
    const rj = r.json;
    if (rj && rj.Sequence_Key__c) estByKey[String(rj.Sequence_Key__c)] = rj;
  }
} catch (e) {}

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });
const currentHour = Number(
  new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Los_Angeles',
    hour: '2-digit',
    hourCycle: 'h23',
  }).format(new Date())
);

function normalizeLastSent(raw) {
  const s = String(raw || '').trim();
  if (!s || s.toUpperCase() === 'NONE') return '';
  if (s === 'Day0' || s === 'Day 0' || s === 'Day_0') return 'Day_0';
  return s;
}

const NEXT_STEP = {
  '': 'Day_1',
  Day_0: 'Day_30',
  Day_1: 'Day_30',
  Day_7: 'Day_30',
  Day_15: 'Day_30',
  Day_30: 'Day_60',
  Day_45: 'Day_60',
  Day_60: 'Day_90',
  Day_90: 'Done',
};

const NEXT_ACTIVE_STEP = {
  Day_1: 'Day_30',
  Day_30: 'Day_60',
  Day_60: 'Day_90',
  Day_90: null,
};

const LEGACY_DAY_30_MIGRATION = new Set(['Day_0', 'Day_1', 'Day_7', 'Day_15']);

function needsLegacyRecalc(lastSent, activeStep) {
  if (LEGACY_DAY_30_MIGRATION.has(lastSent)) return true;
  if (lastSent === 'Day_30' && activeStep !== 'Day_60') return true;
  if (lastSent === 'Day_45') return true;
  return false;
}

function calcLegacyDueDate(lastSent, baseDateStr) {
  if (!baseDateStr) return null;
  const base = new Date(baseDateStr);
  if (isNaN(base.getTime())) return null;
  const offsets = {
    Day_0: 30,
    Day_1: 29,
    Day_7: 23,
    Day_15: 15,
    Day_30: 30,
    Day_45: 15,
  };
  const daysToAdd = offsets[lastSent];
  if (!daysToAdd) return null;
  base.setDate(base.getDate() + daysToAdd);
  return base.toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });
}

const LEGACY_CATCHUP_DAYS = {
  Day_0: 30,
  Day_1: 29,
  Day_7: 23,
};

function isLegacyCatchUp(estRaw, lastSent, activeStep) {
  if (!estRaw) return false;
  if (activeStep) return false;
  return Object.prototype.hasOwnProperty.call(LEGACY_CATCHUP_DAYS, lastSent);
}

function getLegacyCatchUpDays(lastSent) {
  return LEGACY_CATCHUP_DAYS[lastSent] || null;
}

function addDaysFromToday(days) {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });
}

function resolveNextDue(estRaw, lastSent, isLegacyMigration, leadId, activeStep) {
  const lastEmailAt = estRaw ? String(estRaw.Last_Sequence_Email_Sent_At__c || '').trim() : '';
  const nextFollowUp = estRaw
    ? String(estRaw.Next_Follow_Up_Date_Lead__c || '').trim().substring(0, 10)
    : '';

  if (activeStep === 'Day_30' && nextFollowUp && getLegacyCatchUpDays(lastSent) != null) {
    return { nextDue: nextFollowUp };
  }

  if (isLegacyMigration) {
    const catchUpDays = getLegacyCatchUpDays(lastSent);
    if (catchUpDays != null && !activeStep) {
      return { nextDue: addDaysFromToday(catchUpDays) };
    }
    if (lastEmailAt) {
      const legacyDue = calcLegacyDueDate(lastSent, lastEmailAt);
      if (legacyDue) return { nextDue: legacyDue };
    }
    if (LEGACY_DAY_30_MIGRATION.has(lastSent)) {
      if (nextFollowUp) return { nextDue: nextFollowUp };
      const reason =
        'missing legacy timestamp for ' +
        lastSent +
        ' (leadId: ' +
        leadId +
        ', no Last_Sequence_Email_Sent_At__c or Next_Follow_Up_Date_Lead__c)';
      console.log('W6 Normalize skip:', reason);
      return { skip: true, skipReason: reason };
    }
    if (nextFollowUp) return { nextDue: nextFollowUp };
    const reason =
      'missing legacy timestamp for ' +
      lastSent +
      ' (leadId: ' +
      leadId +
      ', no Last_Sequence_Email_Sent_At__c or Next_Follow_Up_Date_Lead__c)';
    console.log('W6 Normalize skip:', reason);
    return { skip: true, skipReason: reason };
  }

  if (!estRaw) return { nextDue: today };
  return { nextDue: nextFollowUp || today };
}

const results = [];

for (const leadItem of leadItems) {
  if (results.length >= PROCESS_LIMIT) break;
  const lead = leadItem.json;

  if (lead.Human_Override__c === true) continue;
  if (lead.IsConverted === true) continue;
  if (lead.Engagement_Status__c !== 'Dormant') continue;
  if (lead.Status === 'Unqualified' || lead.Status === 'Do Not Contact') continue;
  const rawEmail = String(lead.Email || '').trim();
  if (!rawEmail || !rawEmail.includes('@')) continue;

  const seqKey = String(lead.Id) + '_Dormant';
  const estRaw = estByKey[seqKey] || null;

  if (estRaw && ['Paused', 'Stopped', 'Completed'].includes(estRaw.Sequence_Status__c)) continue;

  const lastSent = normalizeLastSent(estRaw ? estRaw.Last_Sequence_Step_Sent__c : '');
  const lastEmailAt = estRaw ? String(estRaw.Last_Sequence_Email_Sent_At__c || '').trim() : '';
  const activeStep = estRaw ? String(estRaw.Active_Sequence_Step__c || '').trim() : '';
  const lastActionAt = estRaw ? String(estRaw.Last_Sequence_Action_At__c || '').trim() : '';

  const isOldCadenceDone = lastSent === 'Day_60' && activeStep !== 'Day_90';
  if (isOldCadenceDone) {
    results.push({
      json: {
        leadId: String(lead.Id),
        firstName: String(lead.FirstName || 'there'),
        lastName: String(lead.LastName || ''),
        email: rawEmail,
        mobilePhone: String(lead.Mobile_Phone_Number__c || lead.MobilePhone || '').trim(),
        leadStatus: String(lead.Status || ''),
        engagementStatus: 'Dormant',
        estId: estRaw ? String(estRaw.Id) : null,
        estExists: !!estRaw,
        sequenceKey: seqKey,
        currentStep: 'Review_Only',
        lastSent,
        lastEmailAt,
        nextDue: today,
        isLegacyMigration: true,
        isOldFinalStep: true,
        exampleOwnerId: String(cfg.exampleOwnerId),
        calendlyLink: String(cfg.calendlyLink),
        colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''),
        senderCcEmail: String(cfg.senderCcEmail || ''),
        day30SmsBody: String(cfg.day30SmsBody || ''),
        today,
      },
    });
    continue;
  }

  if (isLegacyCatchUp(estRaw, lastSent, activeStep)) {
    if (currentHour < 9) continue;
    const catchUpDays = getLegacyCatchUpDays(lastSent);
    const catchUpNextDue = addDaysFromToday(catchUpDays);
    results.push({
      json: {
        leadId: String(lead.Id),
        firstName: String(lead.FirstName || 'there'),
        lastName: String(lead.LastName || ''),
        email: rawEmail,
        mobilePhone: String(lead.Mobile_Phone_Number__c || lead.MobilePhone || '').trim(),
        leadStatus: String(lead.Status || ''),
        engagementStatus: 'Dormant',
        estId: estRaw ? String(estRaw.Id) : null,
        estExists: !!estRaw,
        sequenceKey: seqKey,
        currentStep: 'Day_30',
        nextActiveStep: 'Day_30',
        lastSent,
        lastEmailAt,
        lastActionAt,
        nextDue: catchUpNextDue,
        legacyCatchUp: true,
        legacyCatchUpDays: catchUpDays,
        isLegacyMigration: true,
        isOldFinalStep: false,
        exampleOwnerId: String(cfg.exampleOwnerId),
        calendlyLink: String(cfg.calendlyLink),
        colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''),
        senderCcEmail: String(cfg.senderCcEmail || ''),
        day30SmsBody: String(cfg.day30SmsBody || ''),
        today,
      },
    });
    continue;
  }

  const currentStep = NEXT_STEP[lastSent] || 'Day_1';
  if (currentStep === 'Done') continue;

  const estCurrentStepSent = estRaw ? normalizeLastSent(estRaw.Last_Sequence_Step_Sent__c) : '';
  if (estCurrentStepSent === currentStep && lastEmailAt && ['Day_1','Day_60','Day_90'].includes(currentStep)) continue;

  const isLegacyMigration = needsLegacyRecalc(lastSent, activeStep);
  const dueResult = resolveNextDue(estRaw, lastSent, isLegacyMigration, String(lead.Id), activeStep);
  if (dueResult.skip) continue;
  const nextDue = dueResult.nextDue;

  if (nextDue > today) continue;
  if (currentHour < 9) continue;

  const nextActiveStep = NEXT_ACTIVE_STEP[currentStep] || null;

  results.push({
    json: {
      leadId: String(lead.Id),
      firstName: String(lead.FirstName || 'there'),
      lastName: String(lead.LastName || ''),
      email: rawEmail,
      mobilePhone: String(lead.Mobile_Phone_Number__c || lead.MobilePhone || '').trim(),
      leadStatus: String(lead.Status || ''),
      engagementStatus: 'Dormant',
      estId: estRaw ? String(estRaw.Id) : null,
      estExists: !!estRaw,
      sequenceKey: seqKey,
      currentStep,
      nextActiveStep,
      lastSent,
      lastEmailAt,
      nextDue,
      isLegacyMigration,
      isOldFinalStep: false,
      exampleOwnerId: String(cfg.exampleOwnerId),
      calendlyLink: String(cfg.calendlyLink),
      colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''),
      senderCcEmail: String(cfg.senderCcEmail || ''),
      day30SmsBody: String(cfg.day30SmsBody || ''),
      today,
    },
  });
}

return results.length > 0 ? results : [{ json: { noEligibleLeads: true } }];

// =============================================================
// BUILD DORMANT STEP ACTIONS  (Updated Cadence v2)
//
// Day_1        : Email ONLY (no call task, no SMS task)
// Day_30       : Call Task + SMS Task ONLY — NO EMAIL SENT
// Day_60       : Email ONLY (no call task, no SMS task)
// Day_90       : Final Call Task + Final Email + Status Review Task
// Review_Only  : Status Review Task ONLY (old-cadence Day_60 terminal leads)
//
// Email timestamp: ONLY written on Day_1, Day_60, Day_90
// Action timestamp (Last_Sequence_Action_At__c): written on ALL steps
//
// Active_Sequence_Step__c: set to NEXT upcoming step after current completes
//   Day_1 completes  → set to Day_30
//   Day_30 completes → set to Day_60
//   Day_60 completes → set to Day_90
//   Day_90 completes → cleared (null)
// =============================================================

const STEP_ORDER = ['Day_1', 'Day_30', 'Day_60', 'Day_90', 'Done'];

const DAYS_UNTIL_NEXT = {
  Day_1:  29,
  Day_30: 30,
  Day_60: 30,
  Day_90: 0,
};

const CALL_STEPS    = new Set(['Day_30', 'Day_90']);
const SMS_STEPS     = new Set(['Day_30']);
const REVIEW_STEPS  = new Set(['Day_90', 'Review_Only']);
// Email steps — Day_30 is intentionally excluded
const EMAIL_STEPS   = new Set(['Day_1', 'Day_60', 'Day_90']);

const SUBJECTS = {
  Day_1:  'Reconnecting',
  Day_30: null,
  Day_60: 'Has Timing Improved?',
  Day_90: 'Should I Close the File?',
};

const EMAIL_BODIES = {
  Day_1: (fn) => `<p>Hi ${fn},</p>
<p>I hope you are doing well.</p>
<p>I wanted to reconnect, as it has been some time since we last spoke.</p>
<p>When we last connected, there was interest in discussing ways to enhance customer engagement and support operational objectives.</p>
<p>I wanted to see whether any of those priorities have moved higher on your list this year.</p>
`,

  Day_30: null,

  Day_60: (fn) => `<p>Hi ${fn},</p>
<p>When we last spoke, timing and competing priorities seemed to be the biggest obstacles.</p>
<p>I wanted to check in and see whether anything has changed over the past few months.</p>
`,

  Day_90: (fn) => `<p>Hi ${fn},</p>
<p>I know you are busy, so I will keep this brief.</p>
<p>Since I have not heard back, I am assuming this may not be a priority right now.</p>
<p>Unless I hear otherwise, I will close out my follow-up and reconnect down the road if circumstances change.</p>
<p>If you would still like to explore Example Company solutions, simply reply "interested" and I will reach out.</p>
<p>Thank you again for your time.</p>
`,
};

const buildSig = (sig, cl) => '<br><br>' + sig.replace('CALENDLY_PLACEHOLDER', cl);

const results = [];

for (const item of $input.all()) {
  const ctx = item.json;
  if (!ctx.leadId) continue;

  if (ctx.legacyCatchUp) {
    const catchUpDays = Number(ctx.legacyCatchUpDays) || 23;
    const rawNextDate = new Date();
    rawNextDate.setDate(rawNextDate.getDate() + catchUpDays);
    results.push({ json: {
      ...ctx,
      step: ctx.lastSent,
      nextStep: 'Day_30',
      isLastStep: false,
      needsCallTask: false,
      needsSmsTask: false,
      needsReviewTask: false,
      sendEmail: false,
      rawNextDateStr: rawNextDate.toISOString(),
      emailSubject: null,
      emailBody: null,
      callTaskSubject: null,
      smsTaskSubject: null,
      reviewTaskSubject: null,
      reviewTaskDescription: null,
      smsMsgBody: null,
      ccEmail: String(ctx.senderCcEmail || ''),
      w11Timezone: 'America/Los_Angeles',
      isLegacyMigration: true,
      nextActiveStep: 'Day_30',
      legacyCatchUp: true,
      legacyCatchUpDays: catchUpDays,
      skipStepHistory: true,
      day30SmsBody: ctx.day30SmsBody || '',
    }});
    continue;
  }

  const step = ctx.currentStep;
  const isReviewOnly = (step === 'Review_Only');

  // Review_Only: old-cadence Day_60 terminal — status review task only, no email, no other tasks
  if (isReviewOnly) {
    const leadName = (ctx.firstName + ' ' + ctx.lastName).trim();
    results.push({ json: {
      ...ctx,
      step,
      nextStep: 'Done',
      isLastStep: true,
      needsCallTask: false,
      needsSmsTask: false,
      needsReviewTask: true,
      sendEmail: false,
      rawNextDateStr: new Date().toISOString(),
      emailSubject: null,
      emailBody: null,
      callTaskSubject: null,
      smsTaskSubject: null,
      reviewTaskSubject: 'Old Cadence Day 60 Complete — Status Review Required: ' + (leadName || ctx.email),
      reviewTaskDescription: "Legacy Dormant Review Required\n\nThis lead appears to have completed the old Dormant cadence through Day 60 before the updated cadence was introduced.\n\nAction Required:\n\n* Review the lead manually\n* Determine whether to move to Re-engaged, Follow-Up Requested, Long-Term Nurture, Unqualified, or Do Not Contact\n* Do not automatically send the updated Day 90 final email",
      smsMsgBody: null,
      ccEmail: String(ctx.senderCcEmail || ''),
      w11Timezone: 'America/Los_Angeles',
      isLegacyMigration: true,
      nextActiveStep: null,
    }});
    continue;
  }

  // Normal step processing
  const stepIdx = STEP_ORDER.indexOf(step);
  if (stepIdx < 0) continue;

  const nextStep = (stepIdx < STEP_ORDER.length - 1) ? STEP_ORDER[stepIdx + 1] : 'Done';
  const isLastStep = (step === 'Day_90');
  const needsCallTask = CALL_STEPS.has(step);
  const needsSmsTask = SMS_STEPS.has(step);
  const needsReviewTask = REVIEW_STEPS.has(step);
  const sendEmail = EMAIL_STEPS.has(step);

  const daysUntilNext = DAYS_UNTIL_NEXT[step] || 0;
  const rawNextDate = new Date();
  rawNextDate.setDate(rawNextDate.getDate() + daysUntilNext);
  const rawNextDateStr = daysUntilNext > 0 ? rawNextDate.toISOString() : new Date().toISOString();

  let emailBody = null;
  let emailSubject = null;
  if (sendEmail) {
    const bodyFn = EMAIL_BODIES[step];
    const bodyContent = bodyFn ? bodyFn(ctx.firstName) : null;
    if (!bodyContent) continue;
    emailBody = bodyContent + buildSig(ctx.colleagueSignatureHtml || '', ctx.calendlyLink);
    emailSubject = SUBJECTS[step];
  }

  const leadName = (ctx.firstName + ' ' + ctx.lastName).trim();
  const callTaskSubject   = 'Dormant ' + step.replace('_', ' ') + ' Call — ' + (leadName || ctx.email);
  const reviewTaskSubject = 'Dormant Day 90 — Needs Human Review for Next Steps: ' + (leadName || ctx.email);
  const reviewTaskDescription = needsReviewTask ? "This lead has reached Day 90 of the Dormant Re-Engagement sequence and needs human review for next steps.\n\nPlease review the lead and decide the next status:\n\n* Re-engaged\n* Follow-Up Requested\n* Long-Term Nurture\n* Unqualified\n* Do Not Contact\n\nDo not automatically unqualify this lead. A human should decide the next step." : null;

  // Day_30 SMS: use approved body from config, replace {{First Name}} placeholder.
  // MobilePhone is now in SOQL as ctx.mobilePhone.
  // ⚠️ If SMS_Consent__c or Valid_Mobile__c fields are added to Lead in future,
  //    add them to the SOQL query and gate SMS task creation on those fields here.
  // Approved Day_30 Dormant SMS body (mapped from OLD Dormant Day_15 SMS template).
  // Primary mobile: Mobile_Phone_Number__c (custom field).
  // Fallback mobile: MobilePhone (standard field, label: Prospect Mobile).
  // Resolution already done in Normalize — ctx.mobilePhone holds the resolved value.
  // Do NOT auto-send SMS. Create Salesforce task only.
  const rawSmsBody = String(
    ctx.day30SmsBody ||
    "Hi {{First Name}},\nThis is Example Representative with Example Company.\nIt has been a while since we last connected, and I wanted to see if timing has improved to revisit customer benefits, account reporting, or customer engagement initiatives.\nThank you."
  );
  const smsTaskSubject = 'Dormant ' + step.replace('_', ' ') + ' SMS — ' + (leadName || ctx.email);
  const resolvedMobile = ctx.mobilePhone || '';
  const mobileDisplay = resolvedMobile
    ? 'Lead Mobile: ' + resolvedMobile
    : 'Lead Mobile: No mobile number found on Lead.';
  const smsMsgBody =
    rawSmsBody.replace('{{First Name}}', ctx.firstName)
    + '\n\n' + mobileDisplay
    + '\nLead Email: ' + ctx.email;

  results.push({ json: {
    ...ctx,
    step,
    nextStep,
    isLastStep,
    needsCallTask,
    needsSmsTask,
    needsReviewTask,
    sendEmail,
    rawNextDateStr,
    emailSubject,
    emailBody,
    callTaskSubject,
    smsTaskSubject,
    reviewTaskSubject,
    reviewTaskDescription,
    smsMsgBody,
    ccEmail: String(ctx.senderCcEmail || ''),
    w11Timezone: 'America/Los_Angeles',
    isLegacyMigration: ctx.isLegacyMigration || false,
    nextActiveStep: ctx.nextActiveStep || null,
    day30SmsBody: ctx.day30SmsBody || '',
  }});
}

return results.length > 0 ? results : [{ json: { skip: true } }];

const taskByKey = {};
try {
  for (const r of $('Check Existing Call Task').all()) {
    const rj = r.json;
    if (rj && rj.WhoId && rj.Subject) {
      taskByKey[String(rj.WhoId) + '|' + String(rj.Subject)] = String(rj.Id || '');
    }
  }
} catch(e) {}
const ctx = $input.item.json;
if (!ctx || ctx.skip || !ctx.leadId) return [{ json: { skip: true } }];
const lookupKey = String(ctx.leadId) + '|' + String(ctx.callTaskSubject || '');
const callTaskExists = !!taskByKey[lookupKey];
return [{ json: { ...ctx, callTaskExists } }];

const ctx = $input.item.json;
if (!ctx || ctx.skip) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

// =============================================================
// CHECK EMAIL DEDUPE
// For email steps (Day_1/60/90): skip if email already sent within 25h.
// For non-email steps (Day_30): pass through with skip=false.
// Routing then handled by Has Email To Send? IF node.
// =============================================================
const ctx = $input.item.json;
if (!ctx || ctx.noEligibleLeads || ctx.skip) {
  return [{ json: { skip: true, skipReason: 'No eligible lead context' } }];
}
// Non-email steps pass through — no email to dedupe
if (!ctx.sendEmail) {
  return [{ json: { ...ctx, skip: false } }];
}
// Email dedupe check
const currentStep = String(ctx.step || '');
const currentLeadId = String(ctx.leadId || '');
const currentSeqKey = String(ctx.sequenceKey || '');
let estLastStep = String(ctx.lastSent || '');
let estLastEmailAt = '';
try {
  for (const m of $('Merge EST Result').all()) {
    const mj = m.json;
    if (mj && mj.Id && String(mj.Sequence_Key__c || '') === currentSeqKey) {
      estLastStep = String(mj.Last_Sequence_Step_Sent__c || '');
      estLastEmailAt = String(mj.Last_Sequence_Email_Sent_At__c || '');
      break;
    }
  }
} catch(e) {}
if (estLastStep === currentStep && estLastEmailAt) {
  const hoursSince = (Date.now() - new Date(estLastEmailAt).getTime()) / 3600000;
  if (hoursSince < 25) {
    return [{ json: { skip: true, skipReason: 'Email already sent for step ' + currentStep + ' ' + hoursSince.toFixed(1) + 'h ago (leadId: ' + currentLeadId + ')' } }];
  }
}
return [{ json: { ...ctx } }];

// SAFE: $input.item.json is always this lead's context.
// batchSize=1 guarantees only 1 item in flight per loop iteration.
const ctx = $input.item.json;
if (!ctx || ctx.skip) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

// ZERO CROSS-CONTAMINATION PROOF:
// The 'Loop Over Eligible Leads' node has batchSize=1.
// This means at most 1 lead item is ever in flight inside the loop body during any
// single loop iteration. By the time execution reaches this node:
//   - Recover Context After Send has EXACTLY 1 item in its output (the current lead).
//   - $('Recover Context After Send').item.json therefore always === current lead context.
//   - There is no other lead's context that could occupy that node's output.
// This is structurally guaranteed by the loop, not by timing or sequencing assumptions.
//
// $input.item.json = W11 sub-workflow result for this lead (isBusinessDay, nextBusinessDay, localDate).
// We merge W11's date result with the current lead context from Recover Context After Send.
const ctx = $('Recover Context After Send').item.json;
if (!ctx || ctx.skip) {
  return [{ json: { skip: true, skipReason: 'No context from Recover Context After Send' } }];
}
let nextDueDateStr = null;
try {
  const w11 = $input.item.json;
  nextDueDateStr = w11.isBusinessDay === true
    ? String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10)
    : String(w11.nextBusinessDay || '').substring(0, 10);
  if (!nextDueDateStr || nextDueDateStr.length < 8) {
    return [{ json: { skip: true, skipReason: 'W11 returned invalid date: ' + nextDueDateStr } }];
  }
} catch(e) {
  return [{ json: { skip: true, skipReason: 'W11 call failed: ' + String(e.message || e) } }];
}
// Output: full lead context merged with nextDueDateStr from W11.
// Fields: leadId, email, firstName, sequenceKey, step, isLastStep, nextDueDateStr — all from current lead only.
return [{ json: { ...ctx, nextDueDateStr } }];

const ctx = $input.item.json;
if (!ctx || ctx.skip) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

const ctx = $input.item.json;
if (!ctx || ctx.skip) return [{ json: { skip: true } }];
return [{ json: { ...ctx } }];

// Recover full lead context and determine if SMS task already exists.
// Mirrors the Call Task dedupe pattern exactly.
const taskByKey = {};
try {
  for (const r of $('Check Existing SMS Task').all()) {
    const rj = r.json;
    if (rj && rj.WhoId && rj.Subject) {
